{
  "name": "PhysiQuest: Physics Mastery AI",
  "description": "An intelligent physics tutor for JEE, NEET, and Board aspirants that creates personalized study plans and simplifies complex physics concepts.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ExamType {
  JEE = 'JEE (Main + Advanced)',
  NEET = 'NEET',
  BOARDS = 'Class 12 Boards',
}

export enum PrepLevel {
  BEGINNER = 'Beginner',
  INTERMEDIATE = 'Intermediate',
  ADVANCED = 'Advanced',
}

export interface UserProfile {
  name: string;
  examType: ExamType;
  prepLevel: PrepLevel;
  focusTopics: string[];
  availableHoursPerWeek: number;
}

export interface Module {
  id: string;
  title: string;
  description: string;
  subtopics: string[];
  estimatedTime: string;
  priority: 'High' | 'Medium' | 'Low';
}

export interface StudyPlan {
  title: string;
  overview: string;
  modules: Module[];
  tips: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, StudyPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a world-class Physics mentor specializing in competitive exams like JEE (Main/Advanced), NEET, and Class 12 Boards. 
Your mission is to make physics intuitive, logical, and easy. 
Avoid jargon unless necessary, use relatable analogies, and focus on the "why" behind concepts. 
When asked for a study plan, return structured JSON. 
When explaining concepts, use the Feynman technique: explain complex things so simply that a 10-year-old could understand the core idea, then scale up to exam level complexity.`;

export const generateStudyPlan = async (profile: UserProfile): Promise<StudyPlan> => {
  const prompt = `Create a comprehensive Physics study plan for a student named ${profile.name} who is preparing for ${profile.examType}. 
  Their current level is ${profile.prepLevel} and they can dedicate ${profile.availableHoursPerWeek} hours per week. 
  Focus on these topics: ${profile.focusTopics.join(", ")}.
  The output must be a JSON object containing title, overview, modules (id, title, description, subtopics array, estimatedTime, priority), and tips.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          overview: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                subtopics: { type: Type.ARRAY, items: { type: Type.STRING } },
                estimatedTime: { type: Type.STRING },
                priority: { type: Type.STRING }
              },
              required: ["id", "title", "description", "subtopics", "estimatedTime", "priority"]
            }
          },
          tips: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["title", "overview", "modules", "tips"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const startConceptChat = (onChunk: (text: string) => void) => {
  const chat = ai.chats.create({
    model: "gemini-3-pro-preview",
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
    }
  });

  return {
    sendMessage: async (message: string) => {
      const stream = await chat.sendMessageStream({ message });
      for await (const chunk of stream) {
        onChunk(chunk.text || "");
      }
    }
  };
};

import React, { useState } from 'react';
import { UserProfile, ExamType, PrepLevel } from '../types';

interface OnboardingFormProps {
  onSubmit: (profile: UserProfile) => void;
  isLoading: boolean;
}

const OnboardingForm: React.FC<OnboardingFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<UserProfile>({
    name: '',
    examType: ExamType.JEE,
    prepLevel: PrepLevel.BEGINNER,
    focusTopics: [],
    availableHoursPerWeek: 10,
  });

  const [topicInput, setTopicInput] = useState('');

  const addTopic = () => {
    if (topicInput.trim() && !formData.focusTopics.includes(topicInput.trim())) {
      setFormData(prev => ({
        ...prev,
        focusTopics: [...prev.focusTopics, topicInput.trim()]
      }));
      setTopicInput('');
    }
  };

  const removeTopic = (topic: string) => {
    setFormData(prev => ({
      ...prev,
      focusTopics: prev.focusTopics.filter(t => t !== topic)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return alert("Please enter your name");
    onSubmit(formData);
  };

  return (
    <div className="max-w-2xl mx-auto bg-slate-800/50 p-8 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm">
      <h2 className="text-3xl font-bold mb-6 text-indigo-400">Let's Personalize Your Journey</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2">What's your name?</label>
          <input
            type="text"
            required
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={formData.name}
            onChange={e => setFormData({ ...formData, name: e.target.value })}
            placeholder="e.g. Rahul Sharma"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-2">Target Exam</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
              value={formData.examType}
              onChange={e => setFormData({ ...formData, examType: e.target.value as ExamType })}
            >
              {Object.values(ExamType).map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-2">Current Proficiency</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
              value={formData.prepLevel}
              onChange={e => setFormData({ ...formData, prepLevel: e.target.value as PrepLevel })}
            >
              {Object.values(PrepLevel).map(level => (
                <option key={level} value={level}>{level}</option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2">Hours available per week</label>
          <input
            type="range"
            min="1"
            max="60"
            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            value={formData.availableHoursPerWeek}
            onChange={e => setFormData({ ...formData, availableHoursPerWeek: parseInt(e.target.value) })}
          />
          <div className="text-center mt-2 font-mono text-indigo-400">{formData.availableHoursPerWeek} Hours</div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2">Specific Focus Topics</label>
          <div className="flex gap-2 mb-3">
            <input
              type="text"
              className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
              placeholder="e.g. Rotational Mechanics, Optics"
              value={topicInput}
              onChange={e => setTopicInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), addTopic())}
            />
            <button
              type="button"
              onClick={addTopic}
              className="bg-indigo-600 hover:bg-indigo-700 px-4 py-2 rounded-lg font-medium transition-colors"
            >
              Add
            </button>
          </div>
          <div className="flex flex-wrap gap-2">
            {formData.focusTopics.map(topic => (
              <span key={topic} className="bg-indigo-500/20 text-indigo-300 border border-indigo-500/30 px-3 py-1 rounded-full text-sm flex items-center gap-2">
                {topic}
                <button type="button" onClick={() => removeTopic(topic)} className="hover:text-white">&times;</button>
              </span>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-lg transition-all ${
            isLoading 
              ? 'bg-slate-700 cursor-not-allowed text-slate-500' 
              : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 shadow-lg shadow-indigo-500/20'
          }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center gap-3">
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Building your roadmap...
            </span>
          ) : 'Generate My Study Plan'}
        </button>
      </form>
    </div>
  );
};

export default OnboardingForm;

import React from 'react';
import { StudyPlan, Module } from '../types';

