          </svg>
          Study Tips from the Physicist
        </h3>
        <ul className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {plan.tips.map((tip, i) => (
            <li key={i} className="text-slate-400 text-sm flex gap-3">
