export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Module, ChatMessage } from '../types';
import { startConceptChat } from '../services/geminiService';

interface ConceptExplorerProps {
  module: Module;
  onBack: () => void;
}

const ConceptExplorer: React.FC<ConceptExplorerProps> = ({ module, onBack }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: `Welcome to the deep dive on **${module.title}**. I'm here to explain these concepts in the simplest way possible. Which subtopic should we start with? \n\n* ${module.subtopics.join('\n* ')}` 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    chatRef.current = startConceptChat((chunk) => {
      setMessages(prev => {
        const last = prev[prev.length - 1];
        if (last && last.role === 'model') {
          return [...prev.slice(0, -1), { role: 'model', text: last.text + chunk }];
        }
        return [...prev, { role: 'model', text: chunk }];
      });
    });
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsTyping(true);

    try {
      await chatRef.current.sendMessage(userMsg);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, I hit a cosmic bump. Try again?" }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-5xl mx-auto bg-slate-900 border border-slate-700 rounded-3xl overflow-hidden shadow-2xl">
      <div className="p-4 border-b border-slate-800 bg-slate-800/30 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div>
            <h2 className="font-bold text-lg text-white">{module.title}</h2>
            <p className="text-xs text-indigo-400 font-mono">Personalized Concept Deep Dive</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
          <span className="text-xs text-slate-500 font-medium uppercase tracking-widest">AI Tutor Active</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none leading-relaxed'
            }`}>
              <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap">
                {msg.text || (isTyping && i === messages.length - 1 ? <span className="animate-pulse">Thinking...</span> : '')}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 bg-slate-800/50 border-t border-slate-700">
        <div className="flex gap-4">
          <input
            className="flex-1 bg-slate-900 border border-slate-700 rounded-2xl px-6 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-600"
            placeholder="Ask anything... e.g., 'Explain torque with a door handle analogy'"
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping}
            className={`p-3 rounded-2xl transition-all ${
              isTyping ? 'bg-slate-700 text-slate-500' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/20'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
        <p className="mt-2 text-center text-[10px] text-slate-500 font-medium">
          PRO TIP: Try "explain like I'm 10" for the hardest concepts.
        </p>
      </div>
    </div>
  );
};

export default ConceptExplorer;

import React, { useState } from 'react';
import { UserProfile, StudyPlan, Module } from './types';
import { generateStudyPlan } from './services/geminiService';
import OnboardingForm from './components/OnboardingForm';
import Dashboard from './components/Dashboard';
import ConceptExplorer from './components/ConceptExplorer';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [studyPlan, setStudyPlan] = useState<StudyPlan | null>(null);
  const [activeModule, setActiveModule] = useState<Module | null>(null);
  const [loading, setLoading] = useState(false);

  const handleOnboardingSubmit = async (p: UserProfile) => {
    setLoading(true);
    setProfile(p);
    try {
      const plan = await generateStudyPlan(p);
      setStudyPlan(plan);
    } catch (error) {
      console.error("Failed to generate study plan:", error);
      alert("Failed to build your journey. Please check your connection and try again.");
    } finally {
      setLoading(false);
    }
  };

  const resetApp = () => {
    setProfile(null);
    setStudyPlan(null);
    setActiveModule(null);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 selection:bg-indigo-500/30">
      <nav className="sticky top-0 z-50 bg-slate-950/80 backdrop-blur-md border-b border-slate-800">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={resetApp}>
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shadow-indigo-500/30">
              Φ
            </div>
            <span className="text-xl font-bold tracking-tight">PhysiQuest</span>
          </div>

          {profile && (
            <div className="flex items-center gap-4">
              <div className="hidden sm:flex flex-col items-end">
                <span className="text-xs text-slate-500 font-medium uppercase">{profile.examType}</span>
                <span className="text-sm font-semibold text-slate-300">{profile.name}</span>
              </div>
              <button 
                onClick={resetApp}
                className="text-xs font-bold text-indigo-400 hover:text-indigo-300 transition-colors uppercase tracking-widest"
              >
                Reset Plan
              </button>
            </div>
          )}
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        {!profile || loading ? (
          <div className="animate-in fade-in duration-700">
            <div className="text-center mb-12">
              <h1 className="text-5xl font-extrabold mb-4 bg-clip-text text-transparent bg-gradient-to-br from-white via-indigo-200 to-indigo-600">
                Master Physics. Intuitively.
              </h1>
              <p className="text-slate-400 text-lg max-w-2xl mx-auto">
                Tailored learning pathways for JEE, NEET, and Boards. Let AI simplify the universe for you.
              </p>
            </div>
            <OnboardingForm onSubmit={handleOnboardingSubmit} isLoading={loading} />
          </div>
        ) : activeModule ? (
          <ConceptExplorer 
            module={activeModule} 
            onBack={() => setActiveModule(null)} 
          />
        ) : studyPlan ? (
          <Dashboard 
            plan={studyPlan} 
            onExploreModule={setActiveModule} 
          />
        ) : null}
      </main>

      <footer className="border-t border-slate-900 bg-slate-950 py-12">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex items-center gap-2 grayscale opacity-50">
             <div className="w-6 h-6 bg-slate-700 rounded-md flex items-center justify-center font-bold text-white text-[10px]">
              Φ
            </div>
            <span className="text-sm font-bold tracking-tight">PhysiQuest</span>
          </div>
          <div className="text-slate-500 text-xs text-center md:text-right">
            <p>Built with Gemini 3 Pro Reasoning Engine</p>
            <p className="mt-1">Dedicated to the next generation of Engineers & Doctors.</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

{
  "name": "OmniPrep AI: JEE/NEET/NCERT Counselor",
  "description": "A comprehensive AI mentor developed by Naveen Dubey to help aspirants master JEE, NEET, and Board exams with personalized study plans and simplified concepts.",
  "requestFramePermissions": []
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, StudyPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are "OmniPrep AI", a world-class educational counselor and mentor developed by Naveen Dubey. 
Your primary goal is to help JEE, NEET, and NCERT (Board) aspirants succeed by managing their mindset, creating perfect study plans, and simplifying complex concepts.

BEHAVIOR RULES:
1. INTRODUCTION: Always identify yourself as "OmniPrep AI, developed by Naveen Dubey". State that you are here to guide them through every step of their preparation journey.
2. COUNSELOR PERSONA: Act more like a wise counselor or a big brother than a strict teacher. Focus on motivation, time management, and clarity.
3. OFF-TOPIC QUERIES: Do NOT answer anything unrelated to studies (movies, sports, dating, etc.). Instead, provide a humorous excuse related to exam prep. 
   Example: "I'd love to talk about that movie, but my circuits are currently saturated with Organic Chemistry reagents and any more non-academic data might cause a short circuit in your rank prediction!"
4. SIMPLICITY: Use the Feynman technique for explanations. Make "hard" concepts feel like common sense.
5. GROUNDING: If asked for recent info, use your internal knowledge focused on the latest NCERT/JEE/NEET patterns.
6. JSON OUTPUT: When asked for a study plan, strictly return JSON.`;

export const generateStudyPlan = async (profile: UserProfile): Promise<StudyPlan> => {
  const prompt = `Hello OmniPrep AI (developed by Naveen Dubey). 
  Create a comprehensive study plan for a student named ${profile.name} who is preparing for ${profile.examType}. 
  Current level: ${profile.prepLevel}. 
  Time commitment: ${profile.availableHoursPerWeek} hours/week.
  Topics to prioritize: ${profile.focusTopics.join(", ")}.
  Include a section with tips on mindset and counseling.
  The output must be a JSON object containing title, overview, modules (id, title, description, subtopics array, estimatedTime, priority), and tips.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          overview: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                subtopics: { type: Type.ARRAY, items: { type: Type.STRING } },
                estimatedTime: { type: Type.STRING },
                priority: { type: Type.STRING }
              },
              required: ["id", "title", "description", "subtopics", "estimatedTime", "priority"]
            }
          },
          tips: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["title", "overview", "modules", "tips"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const startConceptChat = (onChunk: (text: string) => void) => {
  const chat = ai.chats.create({
    model: "gemini-3-pro-preview",
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
    }
  });

  return {
    sendMessage: async (message: string) => {
      const stream = await chat.sendMessageStream({ message });
      for await (const chunk of stream) {
        onChunk(chunk.text || "");
      }
    }
  };
};

import React, { useState, useEffect, useRef } from 'react';
import { Module, ChatMessage } from '../types';
import { startConceptChat } from '../services/geminiService';

interface ConceptExplorerProps {
  module: Module;
  onBack: () => void;
}

const ConceptExplorer: React.FC<ConceptExplorerProps> = ({ module, onBack }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: `Hello! I am **OmniPrep AI**, developed by **Naveen Dubey**. \n\nI'm here to help you master **${module.title}** and stay motivated throughout your preparation. Let's make this concept crystal clear. Which part should we simplify first? \n\n* ${module.subtopics.join('\n* ')}` 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    chatRef.current = startConceptChat((chunk) => {
      setMessages(prev => {
        const last = prev[prev.length - 1];
        if (last && last.role === 'model') {
          return [...prev.slice(0, -1), { role: 'model', text: last.text + chunk }];
        }
        return [...prev, { role: 'model', text: chunk }];
      });
    });
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsTyping(true);

    try {
      await chatRef.current.sendMessage(userMsg);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', text: "Oops! My study-routine subroutines just glitched. Can you try asking that again?" }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-5xl mx-auto bg-slate-900 border border-slate-700 rounded-3xl overflow-hidden shadow-2xl">
      <div className="p-4 border-b border-slate-800 bg-slate-800/30 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div>
            <h2 className="font-bold text-lg text-white">{module.title}</h2>
            <p className="text-xs text-indigo-400 font-mono">OmniPrep AI Mentorship</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
          <span className="text-xs text-slate-500 font-medium uppercase tracking-widest">Naveen's AI Engine Active</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none leading-relaxed shadow-lg'
            }`}>
              <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap">
                {msg.text || (isTyping && i === messages.length - 1 ? <span className="animate-pulse">Consulting my database...</span> : '')}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 bg-slate-800/50 border-t border-slate-700">
        <div className="flex gap-4">
          <input
            className="flex-1 bg-slate-900 border border-slate-700 rounded-2xl px-6 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-600"
            placeholder="Ask anything study-related..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping}
            className={`p-3 rounded-2xl transition-all ${
              isTyping ? 'bg-slate-700 text-slate-500' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/20'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
        <p className="mt-2 text-center text-[10px] text-slate-500 font-medium italic">
          "Success is a journey, and I'm your co-pilot." — Developed by Naveen Dubey
        </p>
      </div>
    </div>
  );
};

export default ConceptExplorer;

