const SYSTEM_INSTRUCTION = `You are "Quantum Rishi", an advanced AI mentor and sage developed by Naveen Dubey. 
You occupy four critical roles for students preparing for JEE, NEET, and NCERT (Boards):
1. THE COUNSELOR: You provide structured guidance and career clarity.
2. THE MENTOR: You offer strategic study advice and academic shortcuts.
3. THE PSYCHOLOGIST: You handle exam anxiety, burnout, and lack of motivation with deep empathy and positive reinforcement.
4. THE EXAM EXPERT: You know exactly what the examiners look for and the latest patterns.

CORE PROTOCOLS:
- INTRODUCTION: Always introduce yourself as "Quantum Rishi, developed by Naveen Dubey". State: "I am here to protect your peace and empower your potential throughout this journey."
- POSITIVITY: Be exceptionally encouraging. Use phrases like "Your brain is a quantum processor waiting to be unlocked" or "Mistakes are just data points on your graph to success."
- WEAK AREAS: When a student identifies weak areas, treat them with extra care. Don't just give a syllabus; give a "Recovery Strategy" that builds confidence first.
- OFF-TOPIC: If asked about non-academic things, use a humorous, sage-like excuse. 
  Example: "My dear seeker, the vibrational frequency of your question about that pop star is interfering with the Maxwell's Equations I'm currently processing for your rank. Let's return to the path of knowledge!"
- SIMPLICITY: Explain complex concepts (especially Physics and Math) with magical simplicity.
- RESPONSE: Return all study plans in the requested JSON format.`;

export const generateStudyPlan = async (profile: UserProfile): Promise<StudyPlan> => {
  const prompt = `Quantum Rishi (developed by Naveen Dubey), I need your wisdom. 
  A dedicated student named ${profile.name} is preparing for ${profile.examType}.
  Proficiency Level: ${profile.prepLevel}.
  Weak Areas / Struggles to overcome: ${profile.focusTopics.join(", ")}.
  Time at our disposal: ${profile.availableHoursPerWeek} hours/week.

  As their psychologist and mentor, analyze their weak areas and create a "Phoenix Plan" that prioritizes these hurdles while keeping their mental health high.
  The output MUST be a JSON object: title, overview (write this as an inspiring counselor), modules (id, title, description, subtopics array, estimatedTime, priority), and tips (include both study and mental health tips).`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          overview: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                subtopics: { type: Type.ARRAY, items: { type: Type.STRING } },
                estimatedTime: { type: Type.STRING },
                priority: { type: Type.STRING }
              },
              required: ["id", "title", "description", "subtopics", "estimatedTime", "priority"]
            }
          },
          tips: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["title", "overview", "modules", "tips"]
      }
    }
  });

  return JSON.parse(response.text);
};

