import React, { useState } from 'react';
import { UserProfile, ExamType, PrepLevel } from '../types';

interface OnboardingFormProps {
  onSubmit: (profile: UserProfile) => void;
  isLoading: boolean;
}

const OnboardingForm: React.FC<OnboardingFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<UserProfile>({
    name: '',
    examType: ExamType.JEE,
    prepLevel: PrepLevel.BEGINNER,
    focusTopics: [],
    availableHoursPerWeek: 15,
  });

  const [topicInput, setTopicInput] = useState('');

  const addTopic = () => {
    if (topicInput.trim() && !formData.focusTopics.includes(topicInput.trim())) {
      setFormData(prev => ({
        ...prev,
        focusTopics: [...prev.focusTopics, topicInput.trim()]
      }));
      setTopicInput('');
    }
  };

  const removeTopic = (topic: string) => {
    setFormData(prev => ({
      ...prev,
      focusTopics: prev.focusTopics.filter(t => t !== topic)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return alert("Please share your name, dear seeker.");
    if (formData.focusTopics.length === 0) return alert("Please tell me at least one weak area so I can help you conquer it.");
    onSubmit(formData);
  };

  return (
    <div className="max-w-2xl mx-auto bg-slate-900/60 p-8 rounded-3xl border border-slate-800 shadow-2xl backdrop-blur-xl">
      <h2 className="text-3xl font-bold mb-2 text-indigo-400">Share Your Challenges</h2>
      <p className="text-slate-500 mb-8 text-sm">To guide you, I first need to understand your hurdles.</p>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2 italic">"What shall I call you?"</label>
          <input
            type="text"
            required
            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all placeholder:text-slate-700"
            value={formData.name}
            onChange={e => setFormData({ ...formData, name: e.target.value })}
            placeholder="Your Name"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-2">Target Exam</label>
            <select
              className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
              value={formData.examType}
              onChange={e => setFormData({ ...formData, examType: e.target.value as ExamType })}
            >
              {Object.values(ExamType).map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-2">Current Mindset/Level</label>
            <select
              className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
              value={formData.prepLevel}
              onChange={e => setFormData({ ...formData, prepLevel: e.target.value as PrepLevel })}
            >
              {Object.values(PrepLevel).map(level => (
                <option key={level} value={level}>{level}</option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2">Weekly Dedication (Hours)</label>
          <input
            type="range"
            min="1"
            max="100"
            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            value={formData.availableHoursPerWeek}
            onChange={e => setFormData({ ...formData, availableHoursPerWeek: parseInt(e.target.value) })}
          />
          <div className="text-right mt-2 font-mono text-indigo-400 text-sm">{formData.availableHoursPerWeek} Hours</div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-2">Your Weak Areas & Struggles</label>
          <p className="text-[10px] text-slate-600 mb-2 uppercase tracking-widest font-bold">List the topics that scare you the most</p>
          <div className="flex gap-2 mb-3">
            <input
              type="text"
              className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 placeholder:text-slate-700"
              placeholder="e.g. Ionic Equilibrium, Magnetism..."
              value={topicInput}
              onChange={e => setTopicInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), addTopic())}
            />
            <button
              type="button"
              onClick={addTopic}
              className="bg-indigo-600 hover:bg-indigo-500 px-6 py-2 rounded-xl font-bold transition-all shadow-lg shadow-indigo-600/20"
            >
              Add
            </button>
          </div>
          <div className="flex flex-wrap gap-2">
            {formData.focusTopics.map(topic => (
              <span key={topic} className="bg-indigo-500/10 text-indigo-300 border border-indigo-500/30 px-3 py-1.5 rounded-lg text-sm flex items-center gap-2 group animate-in zoom-in-75">
                {topic}
                <button type="button" onClick={() => removeTopic(topic)} className="text-slate-500 hover:text-red-400">&times;</button>
              </span>
            ))}
            {formData.focusTopics.length === 0 && (
              <p className="text-slate-600 text-xs italic py-2">Don't be shy, tell the Rishi where you struggle...</p>
            )}
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className={`w-full py-4 rounded-2xl font-black text-lg tracking-widest uppercase transition-all ${
            isLoading 
              ? 'bg-slate-800 cursor-not-allowed text-slate-600' 
              : 'bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] hover:bg-right text-white shadow-xl shadow-indigo-600/30'
          }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center gap-3">
              <svg className="animate-spin h-5 w-5 text-indigo-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Consulting the Stars...
            </span>
          ) : 'Channel My Success Plan'}
        </button>
      </form>
    </div>
  );
};

export default OnboardingForm;

