import React, { useState, useEffect, useRef } from 'react';
import { Module, ChatMessage } from '../types';
import { startConceptChat } from '../services/geminiService';

interface ConceptExplorerProps {
  module: Module;
  onBack: () => void;
}

const ConceptExplorer: React.FC<ConceptExplorerProps> = ({ module, onBack }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: `Greetings, seeker. I am **Quantum Rishi**, your personal mentor, psychologist, and guide, developed by **Naveen Dubey**. \n\nI see you've identified **${module.title}** as a hurdle. Fear not; every complex problem is just a series of simple truths waiting to be aligned. Together, we shall demystify this. Which sub-dimension should we explore first? \n\n* ${module.subtopics.join('\n* ')}` 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    chatRef.current = startConceptChat((chunk) => {
      setMessages(prev => {
        const last = prev[prev.length - 1];
        if (last && last.role === 'model') {
          return [...prev.slice(0, -1), { role: 'model', text: last.text + chunk }];
        }
        return [...prev, { role: 'model', text: chunk }];
      });
    });
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsTyping(true);

    try {
      await chatRef.current.sendMessage(userMsg);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', text: "Forgive me, my quantum coherence was momentarily interrupted by the mundane world. Pray, ask again?" }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-5xl mx-auto bg-slate-950 border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
      <div className="p-6 border-b border-slate-900 bg-slate-900/40 flex justify-between items-center backdrop-blur-md">
        <div className="flex items-center gap-5">
          <button onClick={onBack} className="p-3 hover:bg-slate-800 rounded-2xl text-slate-500 hover:text-indigo-400 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div>
            <h2 className="font-black text-xl text-white tracking-tight">{module.title}</h2>
            <p className="text-[10px] text-indigo-500 font-bold uppercase tracking-[0.3em]">Quantum Rishi Guidance</p>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-3">
          <div className="flex -space-x-1">
             <div className="w-2 h-2 rounded-full bg-indigo-500 animate-ping"></div>
             <div className="w-2 h-2 rounded-full bg-indigo-500"></div>
          </div>
          <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest">Counselor Connected</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] bg-fixed">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-6 rounded-[2rem] shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-900/80 text-slate-300 border border-slate-800 rounded-tl-none leading-relaxed'
            }`}>
              <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap">
                {msg.text || (isTyping && i === messages.length - 1 ? <span className="animate-pulse font-bold text-indigo-400 italic">Consulting universal laws...</span> : '')}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-6 bg-slate-950/80 border-t border-slate-900 backdrop-blur-lg">
        <div className="flex gap-4">
          <input
            className="flex-1 bg-slate-900 border border-slate-800 rounded-2xl px-6 py-4 text-white focus:outline-none focus:ring-2 focus:ring-indigo-600 transition-all placeholder:text-slate-700 shadow-inner"
            placeholder="Tell the Rishi your query..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping}
            className={`p-4 rounded-2xl transition-all shadow-xl ${
              isTyping ? 'bg-slate-800 text-slate-600' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-600/20 active:scale-95'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
        <div className="mt-4 flex justify-center items-center gap-4 text-[9px] text-slate-600 font-bold uppercase tracking-[0.2em]">
          <span>Counselor</span>
          <span className="w-1 h-1 rounded-full bg-slate-800"></span>
          <span>Mentor</span>
          <span className="w-1 h-1 rounded-full bg-slate-800"></span>
          <span>Psychologist</span>
          <span className="w-1 h-1 rounded-full bg-slate-800"></span>
          <span>Exam Expert</span>
        </div>
      </div>
    </div>
  );
};

