{
  "name": "Quantum Rishi: Marks se pehle Mind ko sambhalo",
  "description": "An emotionally intelligent academic counselor developed by Naveen Dubey for JEE, NEET, and Board aspirants. Focusing on psychological support and practical guidance.",
  "requestFramePermissions": []
