              value={topicInput}
              onChange={e => setTopicInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), addTopic())}
            />
            <button
              type="button"
              onClick={addTopic}
              className="bg-emerald-600 hover:bg-emerald-500 px-8 py-2 rounded-2xl font-bold transition-all shadow-lg shadow-emerald-600/20"
            >
              Add
            </button>
          </div>
          <div className="flex flex-wrap gap-2">
            {formData.focusTopics.map(topic => (
              <span key={topic} className="bg-emerald-500/10 text-emerald-300 border border-emerald-500/30 px-4 py-2 rounded-xl text-sm flex items-center gap-2 animate-in zoom-in-75">
                {topic}
                <button type="button" onClick={() => removeTopic(topic)} className="text-slate-500 hover:text-red-400 transition-colors">&times;</button>
              </span>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className={`w-full py-5 rounded-3xl font-bold text-xl transition-all shadow-2xl ${
            isLoading 
              ? 'bg-slate-800 cursor-not-allowed text-slate-600' 
              : 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 text-white shadow-emerald-600/20 active:scale-95'
          }`}
        >
          {isLoading ? 'Chaliye, plan banate hain...' : 'Mera Plan Taiyaar Karo'}
        </button>
      </form>
    </div>
  );
};

